        if (op == '*' || op == '/') return 2;
        if (op == '+' || op == '-') return 1;
        return 0;
    }

    public String convert(String infix) {
        Deque<Character> stack = new ArrayDeque<>();
        StringBuilder result = new StringBuilder();
        for (char c : infix.toCharArray()) {
            if (Character.isLetterOrDigit(c)) {
                result.append(c);
            } else if (c == '(') {
                stack.push(c);
            } else if (c == ')') {
                // TODO: pop until '(' found, append to result
            } else {
                // TODO: while stack not empty and top has >= precedence, pop and append
                // then push current operator
            }
        }
        // TODO: pop remaining operators
        return result.toString();
    }

    public static void main(String[] args) {
        InfixToPostfix itop = new InfixToPostfix();
        System.out.println(itop.convert("A+B*C"));
        System.out.println(itop.convert("(A+B)*C"));
        System.out.println(itop.convert("A+B*C-D/E"));
    }
}

