public class PostfixEvaluator {

    public int evaluate(String postfix) {
        Deque<Integer> stack = new ArrayDeque<>();
        String[] tokens = postfix.split(" ");
        for (String token : tokens) {
            if (token.matches("-?\\d+")) {
                stack.push(Integer.parseInt(token));
            } else {
                // TODO: pop two operands b and a, apply operator, push result
                // operators: +, -, *, /
            }
        }
        return stack.pop();
    }

    public static void main(String[] args) {
        PostfixEvaluator pe = new PostfixEvaluator();
        System.out.println(pe.evaluate("3 4 +"));
        System.out.println(pe.evaluate("5 1 2 + 4 * + 3 -"));
        System.out.println(pe.evaluate("2 3 1 * + 9 -"));
    }
}

