        this.n = maze.length;
    }

    public List<int[]> solve() {
        boolean[][] visited = new boolean[n][n];
        Deque<int[]> stack = new ArrayDeque<>();
        Deque<List<int[]>> pathStack = new ArrayDeque<>();

