        pathStack.push(new ArrayList<>(List.of(new int[]{0, 0})));
        visited[0][0] = true;

        int[][] dirs = {{0,1},{1,0},{0,-1},{-1,0}};

        while (!stack.isEmpty()) {
            int[] curr = stack.pop();
            List<int[]> path = pathStack.pop();

            if (curr[0] == n-1 && curr[1] == n-1) return path;

            // TODO: for each direction, if in bounds, not wall, not visited:
            //       mark visited, push neighbor, push path + neighbor
        }
        return new ArrayList<>(); // no path
    }

    public static void main(String[] args) {
        int[][] maze = {
            {0, 0, 1, 0},
            {1, 0, 0, 0},
            {1, 1, 0, 1},
            {0, 0, 0, 0}
        };
        MazeSolver ms = new MazeSolver(maze);
        List<int[]> path = ms.solve();
        System.out.println("Path length: " + path.size());
